import React, { useState, useEffect } from "react";

const AdminUsers = () => {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const token = localStorage.getItem("adminToken");

  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    try {
      setLoading(true);
      const res = await fetch("http://localhost:5000/api/admin/users", {
        headers: { Authorization: `Bearer ${token}` },
      });

      const data = await res.json();

      if (!Array.isArray(data)) {
        setError("Dữ liệu người dùng không hợp lệ");
        return;
      }

      setUsers(data);
    } catch (err) {
      console.error(err);
      setError("Không thể tải danh sách người dùng");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-6">
      <h1 className="text-3xl font-bold text-[#e06c7f] mb-6 flex items-center gap-2">
        👤 Quản lý người dùng
      </h1>

      {/* STATS */}
      <div className="grid grid-cols-3 gap-4 mb-6">
        <div className="p-4 bg-white border rounded-lg shadow flex flex-col items-center">
          <p className="text-gray-600">Tổng người dùng</p>
          <p className="text-3xl font-bold text-[#e06c7f]">{users.length}</p>
        </div>
        <div className="p-4 bg-white border rounded-lg shadow flex flex-col items-center">
          <p className="text-gray-600">Quản trị viên</p>
          <p className="text-3xl font-bold text-[#8b5e3c]">
            {users.filter((u) => u.role === "admin").length}
          </p>
        </div>
        <div className="p-4 bg-white border rounded-lg shadow flex flex-col items-center">
          <p className="text-gray-600">Người dùng thường</p>
          <p className="text-3xl font-bold text-[#3e2f2f]">
            {users.filter((u) => u.role !== "admin").length}
          </p>
        </div>
      </div>

      {/* ERROR */}
      {error && (
        <div className="p-3 bg-red-100 text-red-700 border border-red-300 rounded-lg mb-4">
          ❌ {error}
          <button onClick={fetchUsers} className="underline ml-2">
            Thử lại
          </button>
        </div>
      )}

      {/* LOADING */}
      {loading ? (
        <div className="text-center py-10">
          <div className="animate-spin w-8 h-8 border-4 border-[#e06c7f] border-t-transparent rounded-full mx-auto"></div>
          <p className="mt-2 text-gray-500">Đang tải...</p>
        </div>
      ) : (
        <table className="w-full border-collapse bg-white rounded-xl shadow overflow-hidden">
          <thead>
            <tr className="bg-[#fceef0] text-[#e06c7f] font-semibold">
              <th className="p-3 text-left">Tên</th>
              <th className="p-3 text-left">Email</th>
              <th className="p-3 text-left">Vai trò</th>
              <th className="p-3 text-left">Ngày tạo</th>
            </tr>
          </thead>
          <tbody>
            {users.length === 0 ? (
              <tr>
                <td colSpan="4" className="text-center p-4 text-gray-500">
                  Không có người dùng nào
                </td>
              </tr>
            ) : (
              users.map((user) => (
                <tr key={user._id} className="border-t hover:bg-[#faf8f6]">
                  <td className="p-3">{user.name}</td>
                  <td className="p-3">{user.email}</td>
                  <td className="p-3">
                    {user.role === "admin" ? (
                      <span className="px-3 py-1 bg-[#fde8eb] text-[#e06c7f] rounded-full text-xs font-semibold">
                        Quản trị viên
                      </span>
                    ) : (
                      <span className="px-3 py-1 bg-gray-100 text-gray-700 rounded-full text-xs">
                        Người dùng
                      </span>
                    )}
                  </td>
                  <td className="p-3">
                    {new Date(user.createdAt).toLocaleDateString("vi-VN")}
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      )}
    </div>
  );
};

export default AdminUsers;
